2134	// matchesWhere returns true if the bead satisfies all key=value predicates.
2135	// It checks known struct fields first, then falls back to Extra.
2136	func matchesWhere(b Bead, where map[string]string) bool {
2137		for k, v := range where {
2138			var actual string
2139			switch k {
2140			case "id":
2141				actual = b.ID
2142			case "title":
2143				actual = b.Title
2144			case "status":
2145				actual = b.Status
2146			case "issue_type":
2147				actual = b.IssueType
2148			case "owner":
2149				actual = b.Owner
2150			case "assignee":
2151				actual = b.Owner
2152			case "parent":
2153				actual = b.Parent
2154			case "description":
2155				actual = b.Description
2156			case "acceptance":
2157				actual = b.Acceptance
2158			case "notes":
2159				actual = b.Notes
2160			default:
2161				// Fall back to Extra map for unknown/workflow-specific fields
2162				if b.Extra != nil {
2163					if ev, ok := b.Extra[k]; ok {
2164						actual = fmt.Sprintf("%v", ev)
2165					}
2166				}
2167			}
2168			if actual != v {
2169				return false
2170			}
2171		}
2172		return true
2173	}
