2187	func (s *Store) classifyLifecycleQueue(beads []Bead, now time.Time) []lifecycleQueueEntry {
2188		statusMap := make(map[string]string)
2189		childCount := make(map[string]int)
2190		openChildCount := make(map[string]int)
2191		for _, b := range beads {
2192			statusMap[b.ID] = b.Status
2193			if b.Parent != "" {
2194				childCount[b.Parent]++
2195				if b.Status != StatusClosed {
2196					openChildCount[b.Parent]++
2197				}
2198			}
2199		}
2200	
2201		// Read origin HEAD once per pass for rev-bound cooldown auto-invalidation.
2202		originHead := originMainHead(s.workingDir())
2203	
2204		entries := make([]lifecycleQueueEntry, 0, len(beads))
2205		for _, b := range beads {
2206			unclosed := unclosedDependencyIDs(b, statusMap)
2207			retryAfter, retryActive := activeRetryCooldown(b, now, originHead)
2208			executionEligible, executionEligibleKnown := lifecycleExecutionEligible(b)
2209			supersededBy := lifecycleSupersededBy(b)
2210			claimFresh := (b.Status == StatusOpen || b.Status == StatusInProgress) && !claimLeaseIsStale(s, b.Extra, b.ID)
2211			entry := lifecycleQueueEntry{
2212				Bead:                 b,
2213				UnclosedDepIDs:       unclosed,
2214				RetryAfter:           retryAfter,
2215				LastStatus:           extraStringVal(b.Extra, ExtraLastStatus),
2216				LastDetail:           extraStringVal(b.Extra, ExtraLastDetail),
2217				ExecutionSkipReason:  extraStringVal(b.Extra, ExtraExecutionReason),
2218				SupersededBy:         supersededBy,
2219				EpicClosureCandidate: isEpicClosureCandidate(b, openChildCount[b.ID], childCount[b.ID]),
2220			}
2221			entry.Decision = EvaluateLifecycleQueue(LifecycleQueueFacts{
2222				Status:                 b.Status,
2223				Dependencies:           lifecycleDependencyStates(b, statusMap),
2224				ClaimFresh:             claimFresh,
2225				RetryCooldownActive:    retryActive,
2226				ExecutionEligible:      executionEligible,
2227				ExecutionEligibleKnown: executionEligibleKnown,
2228				SupersededBy:           supersededBy,
2229				EpicContainer:          isOrdinaryEpicContainer(b, openChildCount[b.ID], childCount[b.ID]),
2230				ExternalBlockerReason:  extraStringVal(b.Extra, ExtraLifecycleExternalBlockerReason),
2231				LegacyLabels:           b.Labels,
2232			})
2233			entries = append(entries, entry)
2234		}
2235		return entries
2236	}
