2260	// activeRetryCooldown returns the retry-after time and whether the cooldown is
2261	// still active for bead b. When work-cooldown-base-rev is set and
2262	// originHead has advanced past that rev (i.e., originHead != baseRev and both
2263	// are non-empty), the cooldown auto-clears regardless of wall-clock expiry —
2264	// the world-state that caused the cooldown has changed. See TD-031 §5 invariant.
2265	// originHead should be the current origin/main HEAD, read once per
2266	// ready-queue evaluation pass (not per bead).
2267	func activeRetryCooldown(b Bead, now time.Time, originHead string) (time.Time, bool) {
2268		retryAfterStr := extraStringVal(b.Extra, ExtraRetryAfter)
2269		if retryAfterStr == "" {
2270			return time.Time{}, false
2271		}
2272		retryAfter, err := time.Parse(time.RFC3339, retryAfterStr)
2273		if err != nil {
2274			return time.Time{}, false
2275		}
2276		// Rev-bound auto-invalidation: if origin/main has advanced since this
2277		// cooldown was set, the fix may already be in and the cooldown should clear.
2278		baseRev := extraStringVal(b.Extra, ExtraCooldownBaseRev)
2279		if baseRev != "" && originHead != "" && originHead != baseRev {
2280			return time.Time{}, false
2281		}
2282		return retryAfter, retryAfter.After(now)
2283	}
