2371	func (s *Store) ReadyExecutionBreakdown() (ReadyExecutionBreakdown, error) {
2372		out := ReadyExecutionBreakdown{}
2373		beads, err := s.ReadAll(context.Background())
2374		if err != nil {
2375			return out, err
2376		}
2377		now := time.Now().UTC()
2378		var soonestRetry time.Time
2379		for _, entry := range s.classifyLifecycleQueue(beads, now) {
2380			switch entry.Decision.Bucket {
2381			case LifecycleBucketReady:
2382				out.ExecutionReady = append(out.ExecutionReady, entry.ID)
2383			case LifecycleBucketWaitingDependencies:
2384				out.DependencyWaiting = append(out.DependencyWaiting, entry.ID)
2385			case LifecycleBucketRetryCooldown:
2386				out.RetryCooldown = append(out.RetryCooldown, entry.ID)
2387				if !entry.RetryAfter.IsZero() && (soonestRetry.IsZero() || entry.RetryAfter.Before(soonestRetry)) {
2388					soonestRetry = entry.RetryAfter
2389				}
2390			case LifecycleBucketEpicContainer:
2391				if entry.EpicClosureCandidate {
2392					out.EpicClosureCandidates = append(out.EpicClosureCandidates, entry.ID)
2393				} else {
2394					out.Epics = append(out.Epics, entry.ID)
2395				}
2396			case LifecycleBucketNotEligible:
2397				out.NotEligible = append(out.NotEligible, entry.ID)
2398			case LifecycleBucketSuperseded:
2399				out.Superseded = append(out.Superseded, entry.ID)
2400			case LifecycleBucketBlockedExternal:
2401				out.ExternalBlocked = append(out.ExternalBlocked, entry.ID)
2402			case LifecycleBucketProposed:
2403				out.ProposedOperatorAttention = append(out.ProposedOperatorAttention, entry.ID)
2404			}
2405		}
2406		if !soonestRetry.IsZero() {
2407			out.NextRetryAfter = soonestRetry.Format(time.RFC3339)
2408		}
2409		out.HumanReviewBlockers, out.HumanReviewBlockedTotal = humanReviewBlockerPressure(beads)
2410		return out, nil
2411	}
