2413	func humanReviewBlockerPressure(beads []Bead) ([]HumanReviewBlockerPressure, int) {
2414		byID := make(map[string]Bead, len(beads))
2415		reverseDeps := make(map[string][]string, len(beads))
2416		for _, b := range beads {
2417			byID[b.ID] = b
2418			if !activeForDependencyPressure(b) {
2419				continue
2420			}
2421			for _, dep := range b.Dependencies {
2422				if dep.DependsOnID == "" {
2423					continue
2424				}
2425				reverseDeps[dep.DependsOnID] = append(reverseDeps[dep.DependsOnID], b.ID)
2426			}
2427		}
2428	
2429		var blockers []HumanReviewBlockerPressure
2430		totalBlocked := map[string]struct{}{}
2431		for _, b := range beads {
2432			if !isHumanReviewBlocker(b) {
2433				continue
2434			}
2435			seen := map[string]struct{}{}
2436			var walk func(string)
2437			walk = func(id string) {
2438				for _, childID := range reverseDeps[id] {
2439					if childID == b.ID {
2440						continue
2441					}
2442					child, ok := byID[childID]
2443					if !ok || !activeForDependencyPressure(child) {
2444						continue
2445					}
2446					if _, exists := seen[childID]; exists {
2447						continue
2448					}
2449					seen[childID] = struct{}{}
2450					totalBlocked[childID] = struct{}{}
2451					walk(childID)
2452				}
2453			}
2454			walk(b.ID)
2455			if len(seen) == 0 {
2456				// A proposed/needs-human bead with no active downstream is operator
2457				// attention only; it does not contribute to HumanReviewBlockers.
2458				continue
2459			}
2460			blockers = append(blockers, HumanReviewBlockerPressure{
2461				ID:                     b.ID,
2462				Title:                  b.Title,
2463				Priority:               b.Priority,
2464				DownstreamBlockedCount: len(seen),
2465			})
2466		}
2467	
2468		sort.SliceStable(blockers, func(i, j int) bool {
2469			if blockers[i].Priority != blockers[j].Priority {
2470				return blockers[i].Priority < blockers[j].Priority
2471			}
2472			return blockers[i].ID < blockers[j].ID
2473		})
2474		return blockers, len(totalBlocked)
2475	}
