2477	func isHumanReviewBlocker(b Bead) bool {
2478		// Post-lifecycle: proposed status is the canonical operator-attention signal.
2479		if b.Status == StatusProposed {
2480			return true
2481		}
2482		// Legacy: open beads with investigation/human-review labels still count.
2483		if b.Status != StatusOpen {
2484			return false
2485		}
2486		for _, label := range b.Labels {
2487			switch label {
2488			case LabelNeedsHuman, LabelNeedsInvestigation, LabelNoChangesUnverified, LabelNoChangesUnjustified:
2489				return true
2490			}
2491		}
2492		return false
2493	}
