2609			case LifecycleBucketBlockedExternal:
2610				reason := entry.Decision.ExternalBlockerReason
2611				if reason == "" && len(entry.Decision.Issues) > 0 {
2612					reason = entry.Decision.Issues[0].Detail
2613				}
2614				entries = append(entries, BlockedBead{
2615					Bead: entry.Bead,
2616					Blocker: Blocker{
2617						Kind:   BlockerKindBlockedStatus,
2618						Reason: reason,
2619					},
2620				})
2621			case LifecycleBucketProposed:
2622				entries = append(entries, BlockedBead{
2623					Bead: entry.Bead,
2624					Blocker: Blocker{
2625						Kind:   BlockerKindOperatorAttention,
2626						Reason: "status=proposed requires operator attention",
2627					},
2628				})
2629			case LifecycleBucketEpicContainer:
2630				entries = append(entries, BlockedBead{
2631					Bead: entry.Bead,
2632					Blocker: Blocker{
2633						Kind:   BlockerKindEpicOnly,
2634						Reason: "ordinary ddx work skips epic/container beads",
