2651					},
2652				})
2653			case LifecycleBucketRetryCooldown:
2654				entries = append(entries, BlockedBead{
2655					Bead: entry.Bead,
2656					Blocker: Blocker{
2657						Kind:           BlockerKindRetryCooldown,
2658						NextEligibleAt: entry.RetryAfter.UTC().Format(time.RFC3339),
2659						LastStatus:     entry.LastStatus,
2660						LastDetail:     entry.LastDetail,
2661					},
2662				})
2663			}
