2666		sort.SliceStable(entries, func(i, j int) bool {
2667			if entries[i].Priority != entries[j].Priority {
2668				return entries[i].Priority < entries[j].Priority
2669			}
2670			if !entries[i].CreatedAt.Equal(entries[j].CreatedAt) {
2671				return entries[i].CreatedAt.Before(entries[j].CreatedAt)
2672			}
2673			return entries[i].ID < entries[j].ID
