2678	// isOrdinaryEpicContainer reports whether bead b should be classified as an
2679	// epic container (LifecycleBucketEpicContainer). It takes openChildCount and
2680	// totalChildCount as separate signals so callers can distinguish three cases:
2681	//
2682	//   - openChildCount > 0: live container gating execution (caller routes to
2683	//     LifecycleBucketEpicContainer).
2684	//   - openChildCount == 0 && totalChildCount > 0: closure candidate (still a
2685	//     container; isEpicClosureCandidate returns true).
2686	//   - totalChildCount == 0: genuinely-undecomposed epic that must not enter
2687	//     the container bucket so the work-loop layer can diagnose it separately.
2688	func isOrdinaryEpicContainer(b Bead, openChildCount, totalChildCount int) bool {
2689		issueType := strings.ToLower(strings.TrimSpace(b.IssueType))
2690		title := strings.ToLower(strings.TrimSpace(b.Title))
2691		explicitEpic := issueType == "epic" || strings.HasPrefix(title, "epic:")
2692		looseEpic := strings.HasPrefix(title, "epic ") && totalChildCount > 0
2693		if !explicitEpic && !looseEpic {
2694			return false
2695		}
2696		return totalChildCount > 0
2697	}
