2699	func isEpicClosureCandidate(b Bead, openChildCount, totalChildCount int) bool {
2700		if totalChildCount == 0 {
2701			return false
2702		}
2703		return isOrdinaryEpicContainer(b, openChildCount, totalChildCount) && openChildCount == 0
2704	}
