2706	func sortBeadsForQueue(beads []Bead) {
2707		sort.SliceStable(beads, func(i, j int) bool {
2708			if beads[i].Priority != beads[j].Priority {
2709				return beads[i].Priority < beads[j].Priority
2710			}
2711			ir, iok := parseQueueRank(beads[i].Extra["queue-rank"])
2712			jr, jok := parseQueueRank(beads[j].Extra["queue-rank"])
2713			if iok != jok {
2714				return iok
2715			}
2716			if iok && jok && ir != jr {
2717				return ir < jr
2718			}
2719			if !beads[i].CreatedAt.Equal(beads[j].CreatedAt) {
2720				return beads[i].CreatedAt.Before(beads[j].CreatedAt)
2721			}
2722			return beads[i].ID < beads[j].ID
2723		})
2724	}
