2732		case int16:
2733			return int(v), true
2734		case int32:
2735			return int(v), true
2736		case int64:
2737			return int(v), true
2738		case uint:
2739			return int(v), true
2740		case uint8:
2741			return int(v), true
2742		case uint16:
2743			return int(v), true
2744		case uint32:
2745			return int(v), true
2746		case uint64:
2747			return int(v), true
2748		case float32:
2749			return int(v), v == float32(int(v))
2750		case float64:
