2767	// Status returns aggregate counts.
2768	func (s *Store) Status() (*StatusCounts, error) {
2769		beads, err := s.ReadAll(context.Background())
2770		if err != nil {
2771			return nil, err
2772		}
2773		ready, err := s.Ready()
2774		if err != nil {
2775			return nil, err
2776		}
2777		workerReady, err := s.ReadyExecution()
2778		if err != nil {
2779			return nil, err
2780		}
2781		needsHuman, err := s.ProposedOperatorAttention()
2782		if err != nil {
2783			return nil, err
2784		}
2785	
2786		// Pull in archive partner so totals survive `bead migrate` — the archive
2787		// only carries closed beads, so Ready/Blocked aren't affected.
2788		seen := make(map[string]bool, len(beads))
2789		all := make([]Bead, 0, len(beads))
2790		for _, b := range beads {
2791			if seen[b.ID] {
2792				continue
2793			}
2794			seen[b.ID] = true
2795			all = append(all, b)
2796		}
2797		if s.Collection == DefaultCollection {
2798			archive := s.archivePartner()
2799			if archived, aerr := archive.ReadAll(context.Background()); aerr == nil {
2800				for _, b := range archived {
2801					if seen[b.ID] {
2802						continue
2803					}
2804					seen[b.ID] = true
2805					all = append(all, b)
2806				}
2807			}
2808		}
2809	
2810		counts := &StatusCounts{
2811			Total:             len(all),
2812			Ready:             len(ready),
2813			WorkerReady:       len(workerReady),
2814			NeedsHuman:        len(needsHuman),
2815			OperatorAttention: len(needsHuman),
2816		}
2817		for _, b := range all {
2818			switch b.Status {
2819			case StatusOpen:
2820				counts.Open++
2821			case StatusInProgress:
2822				counts.InProgress++
2823			case StatusClosed:
2824				counts.Closed++
2825			case StatusBlocked:
2826				counts.Blocked++
2827			case StatusProposed:
2828				counts.Proposed++
2829			case StatusCancelled:
2830				counts.Cancelled++
2831			}
2832		}
2833		for _, entry := range s.classifyLifecycleQueue(beads, time.Now().UTC()) {
2834			switch entry.Decision.Bucket {
2835			case LifecycleBucketWaitingDependencies:
2836				counts.DependencyWaiting++
2837			case LifecycleBucketBlockedExternal:
2838				counts.ExternalBlocked++
2839			}
2840		}
2841		return counts, nil
2842	}
