2844	// DepAdd adds a dependency: id depends on depID.
2845	func (s *Store) DepAdd(id, depID string) error {
2846		return s.WithLock(func() error {
2847			beads, _, err := s.readAllLatestRaw()
2848			if err != nil {
2849				return err
2850			}
2851			byID := make(map[string]*Bead, len(beads))
2852			var target *Bead
2853			depExists := false
2854			for i := range beads {
2855				e := &beads[i]
2856				byID[e.ID] = e
2857				if e.ID == id {
2858					target = e
2859				}
2860				if e.ID == depID {
2861					depExists = true
2862				}
2863			}
2864			if target == nil {
2865				return fmt.Errorf("bead: not found: %s", id)
2866			}
2867			if !depExists {
2868				return fmt.Errorf("bead: dependency not found: %s", depID)
2869			}
2870			if id == depID {
2871				return fmt.Errorf("bead: cannot depend on self")
2872			}
2873			if target.HasDep(depID) {
2874				return nil // already exists
2875			}
2876			parentChain, err := beadParentChain(byID, target.Parent)
2877			if err != nil {
2878				return err
2879			}
2880			if err := rejectAncestorDependency(id, depID, parentChain); err != nil {
2881				return err
2882			}
2883	
2884			// Check for circular dependency
2885			depMap := make(map[string][]string)
2886			for _, b := range beads {
2887				depMap[b.ID] = b.DepIDs()
2888			}
2889			depMap[id] = append(append([]string{}, target.DepIDs()...), depID)
2890			if hasCycle(depMap, id) {
2891				return fmt.Errorf("bead: circular dependency: %s -> %s", id, depID)
2892			}
2893	
2894			target.AddDep(depID, "blocks")
2895			target.UpdatedAt = time.Now().UTC()
2896			return s.WriteAll(beads)
2897		})
2898	}
