2907	// DepTree returns a text representation of the dependency tree.
2908	func (s *Store) DepTree(rootID string) (string, error) {
2909		beads, err := s.ReadAll(context.Background())
2910		if err != nil {
2911			return "", err
2912		}
2913		// Pull in archive partner so the tree survives `bead migrate` — closed
2914		// beads stored only in the archive must still appear.
2915		if s.Collection == DefaultCollection {
2916			archive := s.archivePartner()
2917			if archived, aerr := archive.ReadAll(context.Background()); aerr == nil {
2918				seen := make(map[string]bool, len(beads))
2919				for _, b := range beads {
2920					seen[b.ID] = true
2921				}
2922				for _, b := range archived {
2923					if seen[b.ID] {
2924						continue
2925					}
2926					beads = append(beads, b)
2927				}
2928			}
2929		}
2930		byID := make(map[string]*Bead)
2931		for i := range beads {
2932			byID[beads[i].ID] = &beads[i]
2933		}
2934	
2935		if rootID != "" {
2936			target, ok := byID[rootID]
2937			if !ok {
2938				return "", fmt.Errorf("bead: not found: %s", rootID)
2939			}
2940			var sb strings.Builder
2941			// Walk up: show the dependency chain (what this node depends on)
2942			depChain := s.depChainUp(byID, rootID)
2943			if len(depChain) > 0 {
2944				// Print deps as the tree root(s), with the target as their child
2945				for _, depID := range depChain {
2946					if dep, ok := byID[depID]; ok {
2947						fmt.Fprintf(&sb, "%s [%s] %s\n", dep.ID, dep.Status, dep.Title)
2948					}
2949				}
2950			}
2951			// Print the target node
2952			fmt.Fprintf(&sb, "%s [%s] %s\n", target.ID, target.Status, target.Title)
2953			// Print dependents (what depends on this node)
2954			var children []string
2955			for _, other := range sortedKeys(byID) {
2956				if byID[other].HasDep(rootID) {
2957					children = append(children, other)
2958				}
2959			}
2960			for _, child := range children {
2961				s.printTree(&sb, byID, child, "  ", true)
2962			}
2963			return sb.String(), nil
2964		}
2965	
2966		// Find roots (beads that have no dependencies themselves)
2967		var roots []string
2968		for _, b := range beads {
2969			if len(b.Dependencies) == 0 {
2970				roots = append(roots, b.ID)
2971			}
2972		}
2973		sort.Strings(roots)
2974	
2975		var sb strings.Builder
2976		for i, root := range roots {
2977			s.printTree(&sb, byID, root, "", i == len(roots)-1)
2978		}
2979		return sb.String(), nil
2980	}
