2982	func (s *Store) printTree(sb *strings.Builder, byID map[string]*Bead, id, prefix string, last bool) {
2983		b, ok := byID[id]
2984		if !ok {
2985			return
2986		}
2987	
2988		connector := "├── "
2989		if last {
2990			connector = "└── "
2991		}
2992		if prefix == "" {
2993			connector = ""
2994		}
2995	
2996		fmt.Fprintf(sb, "%s%s%s [%s] %s\n", prefix, connector, b.ID, b.Status, b.Title)
2997	
2998		// Find beads that depend on this one (children in the tree)
2999		var children []string
3000		for _, other := range sortedKeys(byID) {
3001			if byID[other].HasDep(id) {
3002				children = append(children, other)
3003			}
3004		}
3005	
3006		childPrefix := prefix
3007		if prefix != "" {
3008			if last {
3009				childPrefix += "    "
3010			} else {
3011				childPrefix += "│   "
3012			}
3013		}
3014	
3015		for i, child := range children {
3016			s.printTree(sb, byID, child, childPrefix, i == len(children)-1)
3017		}
3018	}
