3029	// beadParentChain returns the chain of parent IDs starting at parentID and
3030	// walking upward through stored parent links. The returned chain excludes the
3031	// child bead itself and includes the offending ancestor if one is found.
3032	func beadParentChain(byID map[string]*Bead, parentID string) ([]string, error) {
3033		if parentID == "" {
3034			return nil, nil
3035		}
3036		chain := make([]string, 0, 4)
3037		seen := make(map[string]bool)
3038		current := parentID
3039		for current != "" {
3040			if seen[current] {
3041				chain = append(chain, current)
3042				return chain, fmt.Errorf("bead: parent cycle detected: %s", strings.Join(chain, " -> "))
3043			}
3044			seen[current] = true
3045			chain = append(chain, current)
3046			next, ok := byID[current]
3047			if !ok || next.Parent == "" {
3048				break
3049			}
3050			current = next.Parent
3051		}
3052		return chain, nil
3053	}
