3055	// rejectAncestorDependency rejects dependency edges that point at a bead in
3056	// the supplied parent chain.
3057	func rejectAncestorDependency(childID, depID string, parentChain []string) error {
3058		for _, ancestorID := range parentChain {
3059			if ancestorID == depID {
3060				return fmt.Errorf("bead: dependency %s is an ancestor in the parent chain for %s: %s", depID, childID, strings.Join(parentChain, " -> "))
3061			}
3062		}
3063		return nil
3064	}
