3086	// detectPrefix derives the bead ID prefix from the repository/directory name,
3087	// following the bd convention (e.g., repo "my-project" → prefix "my-project").
3088	// workingDir is the project root to use for git commands; when empty the
3089	// process working directory is used (legacy behaviour, prone to worktree
3090	// path contamination). Falls back to DefaultPrefix if detection fails.
3091	func detectPrefix(workingDir string) string {
3092		// Try git repo root name first, running from the known project root so
3093		// that linked worktrees (e.g. execute-bead isolated worktrees) do not
3094		// contaminate the prefix with their ephemeral directory names.
3095		cmd := gitpkg.Command(context.Background(), workingDir, "rev-parse", "--show-toplevel")
3096		if out, err := cmd.Output(); err == nil {
3097			root := strings.TrimSpace(string(out))
3098			if root != "" {
3099				return filepath.Base(root)
3100			}
3101		}
3102		// Fall back to the provided working dir, then cwd.
3103		if workingDir != "" {
3104			return filepath.Base(workingDir)
3105		}
3106		if wd, err := os.Getwd(); err == nil {
3107			return filepath.Base(wd)
3108		}
3109		return DefaultPrefix
3110	}
