3177	// hasCycle detects cycles in the dependency graph starting from startID.
3178	func hasCycle(deps map[string][]string, startID string) bool {
3179		visited := make(map[string]bool)
3180		stack := make(map[string]bool)
3181	
3182		var visit func(string) bool
3183		visit = func(id string) bool {
3184			visited[id] = true
3185			stack[id] = true
3186	
3187			for _, dep := range deps[id] {
3188				if !visited[dep] {
3189					if visit(dep) {
3190						return true
3191					}
3192				} else if stack[dep] {
3193					return true
3194				}
3195			}
3196	
3197			stack[id] = false
3198			return false
3199		}
3200	
3201		return visit(startID)
3202	}
