package bead

// queueRankKey is the Extra field used to store operator-assigned queue rank.
// Lower values sort earlier within the same priority bucket. Beads without
// this key sort after ranked beads, then by created_at, then by ID.
const queueRankKey = "queue-rank"

// queueRankStep is the default gap between ranks when renormalizing a bucket.
const queueRankStep = 10

// Package queue provides operator-facing queue-ordering helpers for the bead
// tracker. These helpers own the workflow concern of maintaining sparse rank
// ordering within priority buckets; the core bead package owns persistence.
package queue

import (
	"context"
	"fmt"
	"sort"
	"strconv"
	"strings"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
)

const rankStep = 10

// Loader is the persistence interface required by queue helpers.
// *bead.Store satisfies this interface.
type Loader interface {
	ReadAll(ctx context.Context) ([]bead.Bead, error)
	Apply(id string, op bead.Operation) error
}

// Top moves a bead to the front of its priority bucket by assigning the top
// rank value (0). Beads without an explicit rank sort after all ranked beads.
func Top(ctx context.Context, l Loader, id string) error {
	if err := ctx.Err(); err != nil {
		return err
	}
	return l.Apply(id, bead.QueueSetTop{})
}

// Move inserts a bead at the given position (0-based index) within its priority
// bucket. When sparse rank gaps allow it, only the target bead is written;
// otherwise all beads in the bucket are renormalized with step-10 ranks.
func Move(ctx context.Context, l Loader, id string, position int) error {
	if err := ctx.Err(); err != nil {
		return err
	}
	beads, err := l.ReadAll(ctx)
	if err != nil {
		return err
	}

	var target *bead.Bead
	for i := range beads {
		if beads[i].ID == id {
			target = &beads[i]
			break
		}
	}
	if target == nil {
		return fmt.Errorf("bead: not found: %s", id)
	}

	bucket := sortedBucket(beads, target.Priority)
	reduced := make([]bead.Bead, 0, len(bucket))
	for _, b := range bucket {
		if b.ID != id {
			reduced = append(reduced, b)
		}
	}

	if position < 0 {
		position = 0
	}
	if position > len(reduced) {
		position = len(reduced)
	}

	desired := make([]bead.Bead, 0, len(bucket))
	desired = append(desired, reduced[:position]...)
	desired = append(desired, *target)
	desired = append(desired, reduced[position:]...)

	if rank, ok := sparseRank(desired, id); ok {
		return l.Apply(id, bead.QueueSetPosition{Position: rank})
	}

	// Dense: renormalize all beads in the bucket.
	for i, b := range desired {
		if err := l.Apply(b.ID, bead.QueueSetPosition{Position: i * rankStep}); err != nil {
			return err
		}
	}
	return nil
}

// Clear removes the explicit queue rank from a bead, restoring natural ordering.
func Clear(ctx context.Context, l Loader, id string) error {
	if err := ctx.Err(); err != nil {
		return err
	}
	return l.Apply(id, bead.QueueClearOp{})
}

// BucketPosition returns the 0-based index of refID in the sorted priority
// bucket for targetID, after removing targetID from the bucket. Returns -1
// when refID is not found or belongs to a different priority bucket.
// The CLI uses this to convert --before/--after flags to a position index.
func BucketPosition(beads []bead.Bead, targetID, refID string) int {
	var targetPriority, refPriority int
	targetFound, refFound := false, false
	for _, b := range beads {
		if b.ID == targetID {
			targetPriority = b.Priority
			targetFound = true
		}
		if b.ID == refID {
			refPriority = b.Priority
			refFound = true
		}
	}
	if !targetFound || !refFound || targetPriority != refPriority {
		return -1
	}
	bucket := sortedBucket(beads, targetPriority)
	reduced := make([]bead.Bead, 0, len(bucket))
	for _, b := range bucket {
		if b.ID != targetID {
			reduced = append(reduced, b)
		}
	}
	for i, b := range reduced {
		if b.ID == refID {
			return i
		}
	}
	return -1
}

// sortedBucket filters beads by priority and sorts them by queue order:
// explicit rank (ascending), then created_at, then ID.
func sortedBucket(beads []bead.Bead, priority int) []bead.Bead {
	out := make([]bead.Bead, 0, len(beads))
	for _, b := range beads {
		if b.Priority == priority {
			out = append(out, b)
		}
	}
	sort.SliceStable(out, func(i, j int) bool {
		ir, iok := parseRank(out[i])
		jr, jok := parseRank(out[j])
		if iok != jok {
			return iok
		}
		if iok && jok && ir != jr {
			return ir < jr
		}
		if !out[i].CreatedAt.Equal(out[j].CreatedAt) {
			return out[i].CreatedAt.Before(out[j].CreatedAt)
		}
		return out[i].ID < out[j].ID
	})
	return out
}

// parseRank extracts the queue-rank integer from a bead's Extra map.
func parseRank(b bead.Bead) (int, bool) {
	if b.Extra == nil {
		return 0, false
	}
	switch v := b.Extra["queue-rank"].(type) {
	case int:
		return v, true
	case int8:
		return int(v), true
	case int16:
		return int(v), true
	case int32:
		return int(v), true
	case int64:
		return int(v), true
	case uint:
		return int(v), true
	case uint8:
		return int(v), true
	case uint16:
		return int(v), true
	case uint32:
		return int(v), true
	case uint64:
		return int(v), true
	case float32:
		return int(v), v == float32(int(v))
	case float64:
		return int(v), v == float64(int(v))
	case string:
		if n, err := strconv.Atoi(strings.TrimSpace(v)); err == nil {
			return n, true
		}
	}
	return 0, false
}

// sparseRank computes a rank for targetID that fits between its neighbors in
// the desired slice, preserving sparse ordering without renormalizing others.
// Returns (rank, true) when a sparse slot exists; (0, false) when the bucket
// must be renormalized.
func sparseRank(desired []bead.Bead, targetID string) (int, bool) {
	targetIdx := -1
	for i, b := range desired {
		if b.ID == targetID {
			targetIdx = i
			break
		}
	}
	if targetIdx < 0 {
		return 0, false
	}

	// All beads before target must have explicit ranks for sparse-rank to work.
	for i := 0; i < targetIdx; i++ {
		if _, ok := parseRank(desired[i]); !ok {
			return 0, false
		}
	}

	var prevRank *int
	for i := targetIdx - 1; i >= 0; i-- {
		if r, ok := parseRank(desired[i]); ok {
			prevRank = &r
			break
		}
	}

	var nextRank *int
	for i := targetIdx + 1; i < len(desired); i++ {
		if r, ok := parseRank(desired[i]); ok {
			nextRank = &r
			break
		}
	}

	switch {
	case prevRank != nil && nextRank != nil:
		if *nextRank-*prevRank <= 1 {
			return 0, false
		}
		return (*prevRank + *nextRank) / 2, true
	case prevRank != nil:
		return *prevRank + 1, true
	case nextRank != nil:
		return *nextRank - 1, true
	default:
		return 0, true
	}
}

package queue_test

import (
	"context"
	"path/filepath"
	"testing"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	beadqueue "github.com/DocumentDrivenDX/ddx/internal/bead/ops/queue"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

func newStore(t *testing.T) *bead.Store {
	t.Helper()
	s := bead.NewStore(filepath.Join(t.TempDir(), ".ddx"))
	require.NoError(t, s.Init(context.Background()))
	return s
}

func createBead(t *testing.T, s *bead.Store, id, title string, priority int) *bead.Bead {
	t.Helper()
	b := &bead.Bead{
		ID:        id,
		Title:     title,
		Status:    bead.StatusOpen,
		Priority:  priority,
		IssueType: "task",
		CreatedAt: time.Now().UTC(),
		UpdatedAt: time.Now().UTC(),
	}
	require.NoError(t, s.Create(context.Background(), b))
	got, err := s.Get(context.Background(), b.ID)
	require.NoError(t, err)
	return got
}

// TestOpsQueue_Top_MovesBeadToFront verifies that Top sets an explicit rank that
// places the target before unranked beads in the same priority bucket.
func TestOpsQueue_Top_MovesBeadToFront(t *testing.T) {
	t.Parallel()
	s := newStore(t)
	now := time.Now().UTC()

	b1 := &bead.Bead{ID: "a", Title: "A", Status: bead.StatusOpen, Priority: 1, IssueType: "task", CreatedAt: now, UpdatedAt: now}
	b2 := &bead.Bead{ID: "b", Title: "B", Status: bead.StatusOpen, Priority: 1, IssueType: "task", CreatedAt: now.Add(time.Minute), UpdatedAt: now.Add(time.Minute)}
	require.NoError(t, s.Create(context.Background(), b1))
	require.NoError(t, s.Create(context.Background(), b2))

	// b2 was created after b1, so it normally sorts second. Top should move it first.
	require.NoError(t, beadqueue.Top(context.Background(), s, "b"))

	got, err := s.Get(context.Background(), "b")
	require.NoError(t, err)
	require.NotNil(t, got.Extra, "Top must set a queue-rank")
	_, hasRank := got.Extra["queue-rank"]
	assert.True(t, hasRank, "Top must assign queue-rank")

	// b should now sort before a in the ready queue
	ready, err := s.Ready()
	require.NoError(t, err)
	require.Len(t, ready, 2)
	assert.Equal(t, "b", ready[0].ID, "b should be first after Top")
}

// TestOpsQueue_Move_PreservesPriorityBucket verifies that Move sets queue-rank
// without altering the bead's priority field.
func TestOpsQueue_Move_PreservesPriorityBucket(t *testing.T) {
	t.Parallel()
	s := newStore(t)
	now := time.Now().UTC()

	b := &bead.Bead{ID: "x", Title: "X", Status: bead.StatusOpen, Priority: 2, IssueType: "task", CreatedAt: now, UpdatedAt: now}
	require.NoError(t, s.Create(context.Background(), b))

	require.NoError(t, beadqueue.Move(context.Background(), s, "x", 0))

	got, err := s.Get(context.Background(), "x")
	require.NoError(t, err)
	assert.Equal(t, 2, got.Priority, "Move must not change priority")
	_, hasRank := got.Extra["queue-rank"]
	assert.True(t, hasRank, "Move must assign a queue-rank")
}

// TestOpsQueue_Clear_RemovesOperatorOverride verifies that Clear removes the
// queue-rank key, restoring natural ordering.
func TestOpsQueue_Clear_RemovesOperatorOverride(t *testing.T) {
	t.Parallel()
	s := newStore(t)
	now := time.Now().UTC()

	b := &bead.Bead{ID: "y", Title: "Y", Status: bead.StatusOpen, Priority: 1, IssueType: "task", CreatedAt: now, UpdatedAt: now}
	require.NoError(t, s.Create(context.Background(), b))

	require.NoError(t, beadqueue.Top(context.Background(), s, "y"))
	got, err := s.Get(context.Background(), "y")
	require.NoError(t, err)
	_, hasRank := got.Extra["queue-rank"]
	require.True(t, hasRank, "queue-rank should be set before Clear")

	require.NoError(t, beadqueue.Clear(context.Background(), s, "y"))

	cleared, err := s.Get(context.Background(), "y")
	require.NoError(t, err)
	if cleared.Extra != nil {
		_, stillHasRank := cleared.Extra["queue-rank"]
		assert.False(t, stillHasRank, "Clear must remove queue-rank")
	}
}

